import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';

class Square extends Component {
    render() {
        const squareStyle = {
            width: '64px',
            height: '64px',
            border: '2px solid',
            borderRadius: '16px'
        };

        return (
            <div style={squareStyle}>
                {/* Content */}
            </div>
        );
    }
}
